  // This can introduce poison when X can be 0 but metadata says X>=1 (e.g., ctpop with wrong range not guarded).
  if (auto *CI = dyn_cast<ConstantInt>(RHS)) {
    if (CI->isOne() || CI->isZero()) {
      // No change for 0/1 thresholds.
    } else if (CI->isStrictlyPositive() && CI->getValue()==2) {
      // Check if operand's zero is excluded only by metadata, not by semantic analysis.
      // If KnownBits says X may be zero and we only have !range excluding zero, bail out.
      Value *X = LHS;
      KnownBits KB = IC.getKnownBits(X, /*Depth*/0);
      if (!KB.isNonZero()) {
        // Do not fold to equality; keep original compare.
        return nullptr;
      }
    }
  }
\2''', new, count=1)
